class MyCustomJSONHandler(flask.json.provider.DefaultJSONProvider):
    def dumps(self, obj, **kwargs):
        def custom_default(o):
            if isinstance(o, np.ndarray):
                nan_mask = np.isnan(o)
                non_nan = o[~nan_mask]
                nan_count = int(np.sum(nan_mask))
                unique_non_nan = np.unique(non_nan).tolist() if len(non_nan) > 0 else []
                nan_list = [float('nan')] * nan_count
                return unique_non_nan + nan_list
            raise TypeError(f"Object of type {type(o).__name__} is not JSON serializable")
        kwargs.setdefault("default", custom_default)
        return super().dumps(obj, **kwargs)

app.json_provider_class = MyCustomJSONHandler
